INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2588, 223499, 1, 5, '新年', '呼~~总算要过年了，让我们一起祝福新的2004来年会更好！
<br>谁也没想到连续几天阴雨天气之后厦门在年三十这天放了一个晴天，所有的阴霾也随着阳光放晴，路上、行人、车来车往无一不记载着过年的愉悦，哈哈，又过了一年！
<br>几天来都跟着家里人忙里忙外，享受着过年的气氛，享受着排队购买年货的乐趣，年每年都过，不同的是今年有时间陪家人一起忙碌着一切，高兴之余竟也有一丝丝的感动。陪着母亲在雨中穿梭着忙着购买年货，雨越下越大，雨水沿着脸流下，颇有一种老朋友的感觉，厦门也好久没有下雨了，好像。回忆起小时候过年的种种，不禁一笑，围炉自不必说，等着过十二点满大街炮声轰隆的情景仍历历在目，炮声送走旧的一年也迎来新的一岁，一般厦门人在年三十晚上都要“拜天公”，那可是最高兴的事，因为平常都必须早睡，而那一夜可以彻夜不睡跟着跑进跑出，享受通宵的乐趣。而随着厦门禁炮令的推出，在厦门再也听不到那久违的炮声轰隆了，取而代之的是零点钟声敲响时千家万户的电话几乎都占线，手机短信一条接一条地传来，诉说着亲人朋友对新一年的祝愿。以前小时候总是到处收红包现在变成了自己往外送红包，高兴之余也不禁感慨时光的变迁，唉~~该保养了：）
<br>新的一年总算是一个新的开始，团圆的同时也让我们更想念，惦记身在远方的亲人、朋友...祝愿所有的人都能平安快乐！<br><br>---<br><font&nbsp;class="font">陌生的人、陌生的脸孔、陌生的城市、陌生的天空......</font>', '呼~~总算要过年了，让我们一起祝福新的2004来年会更好！

